function setupTabs(){document.querySelectorAll(".tab-button").forEach(function(button){button.addEventListener("click",function(){var target=button.getAttribute("data-tab");document.querySelectorAll(".tab-button").forEach(function(b){b.classList.toggle("active",b===button)});document.querySelectorAll(".tab-panel").forEach(function(panel){panel.classList.toggle("active",panel.id===target)});});});}
