function load(){var s=fresh(),raw=localStorage.getItem(KEY)||localStorage.getItem(OLD_KEY);if(!raw)return s;try{var old=JSON.parse(raw);var m=Object.assign(s,old);m.seeds=Object.assign({},s.seeds,old.seeds||{});m.crops=Object.assign({},s.crops,old.crops||{});m.gear=Object.assign({},s.gear,old.gear||{});m.pets=Object.assign({},s.pets,old.pets||{});m.petLevels=Object.assign({},s.petLevels,old.petLevels||{});m.petWalk=Object.assign({},s.petWalk,old.petWalk||{});m.up=Object.assign({},s.up,old.up||{});m.stats=Object.assign({},s.stats,old.stats||{});m.daily=Object.assign({},s.daily,old.daily||{});m.weather=Object.assign({},s.weather,old.weather||{});m.shop=Object.assign({},s.shop,old.shop||{});m.shop.stock=Object.assign({},s.shop.stock,(old.shop&&old.shop.stock)||{});m.gearShop=Object.assign({},s.gearShop,old.gearShop||{});m.gearShop.stock=Object.assign({},s.gearShop.stock,(old.gearShop&&old.gearShop.stock)||{});m.eggShop=Object.assign({},s.eggShop,old.eggShop||{});m.eggShop.stock=Object.assign({},s.eggShop.stock,(old.eggShop&&old.eggShop.stock)||{});m.eventShop=Object.assign({},s.eventShop,old.eventShop||{});m.eventShop.stock=Object.assign({},s.eventShop.stock,(old.eventShop&&old.eventShop.stock)||{});m.event=Object.assign({},s.event,old.event||{});m.leaderboard=Object.assign({},s.leaderboard,old.leaderboard||{});m.plots=Array.isArray(old.plots)?old.plots:[];Object.keys(m.pets||{}).forEach(function(id){if((m.pets[id]||0)>0&&!m.petLevels[id])m.petLevels[id]=1});if(m.coins===24&&!Object.keys(m.seeds||{}).length&&!Object.keys(m.crops||{}).length)m.coins=40;return m}catch(e){console.warn(e);return s}}
function save(){state.lastSavedAt=Date.now();localStorage.setItem(KEY,JSON.stringify(state));if(el.savedAt)el.savedAt.textContent="Now"}
function weatherById(id){return WEATHER.find(function(w){return w.id===id})||WEATHER[0]}
function activeNightEvent(){return eventWeek()===NIGHT_EVENT_WEEK}
function hourProgress(){return Date.now()%HOUR_MS}
function activeNightWeather(){return activeNightEvent()&&hourProgress()<NIGHT_WEATHER_MS}
function weatherSlot(){return Math.floor(Date.now()/WEATHER_MS)}
function sharedWeatherId(slot){var choices=WEATHER.filter(function(w){return w.id!=="night"}),pick=Math.floor(stockRoll(slot,"weather",41)*choices.length);return (choices[pick]||WEATHER[0]).id}
function rollWeather(){if(!state.weather)state.weather={id:"sunny",nextAt:0};var now=Date.now(),id,nextAt;if(activeNightWeather()){id="night";nextAt=now+(NIGHT_WEATHER_MS-hourProgress())}else{id=sharedWeatherId(weatherSlot());nextAt=(weatherSlot()+1)*WEATHER_MS}state.weather.id=id;state.weather.nextAt=nextAt;return weatherById(id)}
function activeWeather(){return rollWeather()}
function addMutation(list,id){if(!id)return list||[];list=Array.isArray(list)?list:[];if(list.indexOf(id)<0)list.push(id);return list}
function maybeAddMutation(list,id,chance){if(id&&Math.random()<chance)addMutation(list,id);return list}
function mutationValue(muts){muts=Array.isArray(muts)?muts:[];return muts.reduce(function(total,id){return total*(MUTATIONS[id]?MUTATIONS[id].multi:1)},1)}
function mutationLabel(muts){muts=Array.isArray(muts)?muts:[];return muts.map(function(id){return MUTATIONS[id]?MUTATIONS[id].name:""}).filter(Boolean).join(" + ")}
function mutationBadges(muts){muts=Array.isArray(muts)?muts:[];return muts.map(function(id){var m=MUTATIONS[id];return m?"<span class='mutation-badge "+m.cls+"'>"+m.name+"</span>":""}).join("")}
function rollWeight(c,boost){var base={Common:1,Uncommon:1.15,Rare:1.35,Epic:1.6,Legendary:2,Mythic:2.6,Divine:3.4,Prismatic:4.4}[c.rarity]||1;var swing=.55+Math.random()*1.7;if(Math.random()<.08)swing+=Math.random()*1.5;if(Math.random()<.015)swing+=2+Math.random()*2.5;return Math.max(.2,Math.round(base*swing*(1+(Number(boost)||0))*10)/10)}
function weightMultiplier(w){w=Number(w)||1;return Math.max(.25,Math.round((.65+Math.pow(w,.72)*.35)*100)/100)}
function weightLabel(w){w=Number(w)||1;return w.toFixed(1)+" lb"}
function inventoryKey(id,muts,weight){muts=Array.isArray(muts)?muts.slice().sort():[];var parts=[id];if(muts.length)parts.push(muts.join("_"));if(weight)parts.push("w"+Number(weight).toFixed(1));return parts.join("__")}
function parseInventoryKey(key){var parts=String(key).split("__"),muts=[],weight=1;parts.slice(1).forEach(function(part){if(part.charAt(0)==="w")weight=Number(part.slice(1))||1;else muts=part.split("_").filter(Boolean)});return {id:parts[0],mutations:muts,weight:weight}}
function cropDisplayName(c,muts){var label=mutationLabel(muts);return label?label+" "+c.name:c.name}
function crop(id){return CROPS.find(function(c){return c.id===id})}
function gear(id){return GEAR.find(function(g){return g.id===id})}
function rarityRank(rarity){return ["Common","Uncommon","Rare","Epic","Legendary","Mythic","Divine","Prismatic"].indexOf(rarity)}
function unlockCost(c){return c.unlock===0?0:c.seedCost}
function clampUpgradeLevel(level){return Math.min(UPGRADE_MAX_LEVEL,Math.max(0,Number(level)||0))}
function upgradeCost(type,nextLevel){var base=UPGRADE_BASE_COST[type]||100;var curve={plots:1.24,speed:1.2,yield:1.22}[type]||1.2;return Math.round(base*Math.pow(curve,nextLevel-1)+nextLevel*12)}
function upgradeEffectText(type,data){if(type==="plots")return data.count+" total plots";if(type==="speed")return Math.round((1-data.multi)*100)+"% faster growth";return "+"+data.bonus+" crops per harvest"}
function makeUpgrade(type,level){level=clampUpgradeLevel(level);var data={level:level,max:UPGRADE_MAX_LEVEL,label:"Level "+level+" / "+UPGRADE_MAX_LEVEL,cost:level>0?upgradeCost(type,level):0};if(type==="plots")data.count=12+level;if(type==="speed")data.multi=Math.max(.2,1-level*.016);if(type==="yield")data.bonus=Math.floor(level/2);data.effect=upgradeEffectText(type,data);return data}
function up(type){state.up[type]=clampUpgradeLevel(state.up[type]);return makeUpgrade(type,state.up[type])}
function next(type){var level=clampUpgradeLevel(state.up[type]);return level>=UPGRADE_MAX_LEVEL?null:makeUpgrade(type,level+1)}
function plotLimit(){return up("plots").count}
function petLevel(id){return Math.max(1,Math.min(PET_LEVEL_MAX,Math.floor((state.petLevels&&state.petLevels[id])||((state.pets&&state.pets[id])?1:0))))}
function petScale(id){return 1+(petLevel(id)-1)*.12}
function petCooldownScale(id){return Math.max(.35,1-(petLevel(id)-1)*.04)}
function petBonuses(){var b={gold:0,rainbow:0,weather:0,coins:0,speed:0,yield:0,harvests:0};Object.keys(state.pets||{}).forEach(function(id){var count=state.pets[id]||0,p=PETS[id],scale=petScale(id);if(!p||!count)return;["gold","rainbow","weather","coins","speed"].forEach(function(k){b[k]+=(p[k]||0)*count*scale});["yield","harvests"].forEach(function(k){b[k]+=Math.floor((p[k]||0)*count*scale)})});b.speed=Math.min(.45,b.speed);b.coins=Math.min(1.5,b.coins);b.gold=Math.min(.35,b.gold);b.rainbow=Math.min(.18,b.rainbow);b.weather=Math.min(.45,b.weather);return b}
function growMs(c){return Math.max(4000,Math.round(c.grow*up("speed").multi*(1-petBonuses().speed)))}
function fitPlots(){while(state.plots.length<plotLimit())state.plots.push(null);if(state.plots.length>plotLimit())state.plots=state.plots.slice(0,plotLimit())}
function tick(){rollWeather();ensureShopStock();ensureGearStock();ensureEggStock();ensureEventStock();movePets();applyNightOwl();applyWeatherMutations();drawPlots();drawPets();drawShop();drawGearShop();drawPetShop();drawEvents();stats()}
function render(){fitPlots();rollDaily();rollWeather();ensureShopStock();ensureGearStock();ensureEggStock();ensureEventStock();movePets();applyWeatherMutations();stats();drawSelected();drawPlots();drawPets();drawShop();drawGearShop();drawPetShop();drawInv();drawQuests();drawEvents();drawUpgrades();drawLeaderboard()}
function stats(){var w=weatherById(state.weather&&state.weather.id);el.coins.textContent=num(state.coins);el.plotsOwned.textContent=plotLimit();if(el.weatherNow)el.weatherNow.textContent=w.icon+" "+w.name;if(el.restocksNow)el.restocksNow.textContent="Seeds "+time(state.shop.nextAt-Date.now())+" / Event "+time(state.eventShop.nextAt-Date.now())}
function applyWeatherMutations(){var w=weatherById(state.weather&&state.weather.id),pb=petBonuses();state.plots.forEach(function(p){if(!p)return;var c=crop(p.id);if(!c)return;var boost=p.mutationBoost||0,progress=(Date.now()-p.at)/(p.duration||growMs(c));if(progress>.2){maybeAddMutation(p.mutations,"gold",boost*.18);maybeAddMutation(p.mutations,"rainbow",boost*.055);maybeAddMutation(p.mutations,w.mutation,.035+pb.weather+boost);}});}
function drawSelected(){if(state.selectedType==="gear"){var g=gear(state.selected);el.selectedSeed.textContent=g?g.icon+" "+g.name+" selected":"No seed or gear selected";return}var c=crop(state.selected);el.selectedSeed.textContent=c?c.icon+" "+c.name+" selected":"No seed or gear selected"}
function drawPlots(){el.gardenGrid.innerHTML="";state.plots.forEach(function(p,i){var b=document.createElement("button");b.className="plot";b.type="button";b.onclick=function(){plotClick(i)};b.innerHTML="<span class='crop'></span><span class='plot-name'></span><span class='plot-mutations'></span><span class='plot-action'></span><span class='plot-time'></span><span class='progress'><i></i></span>";var ic=b.querySelector(".crop"),nm=b.querySelector(".plot-name"),mb=b.querySelector(".plot-mutations"),ac=b.querySelector(".plot-action"),tm=b.querySelector(".plot-time");if(!p){b.classList.add("empty");nm.textContent="Empty Plot";ac.textContent=state.selectedType==="seed"?"Plant":"Empty";tm.textContent=state.selectedType==="seed"?"Plant selected seed":"Select a seed"}else{var c=crop(p.id);if(!c){state.plots[i]=null;return}var d=p.duration||growMs(c),done=Math.min(1,Math.max(0,(Date.now()-p.at)/d));b.classList.toggle("ready",done>=1);b.style.setProperty("--progress",Math.round(done*100)+"%");ic.style.setProperty("--scale",String(.35+done*.75));ic.textContent=c.icon;nm.textContent=c.name;mb.innerHTML=mutationBadges(p.mutations);(p.mutations||[]).forEach(function(id){var m=MUTATIONS[id];if(m)b.classList.add(m.cls)});ac.textContent=state.selectedType==="gear"?"Use Gear":done>=1?"Harvest":"Growing";tm.textContent=(done>=1?(p.harvestsLeft>1?"Ready - "+p.harvestsLeft+" harvests left":"Ready to harvest"):time(d-(Date.now()-p.at)))+(p.sizeBoost?" - Size +"+Math.round(p.sizeBoost*100)+"%":"")+(p.mutationBoost?" - Mut +"+Math.round(p.mutationBoost*100)+"%":"")}el.gardenGrid.appendChild(b)})}
function ownedPetEntries(){var entries=[];Object.keys(state.pets||{}).forEach(function(id){var p=PETS[id],count=state.pets[id]||0;if(!p||!count)return;for(var i=0;i<Math.min(count,3);i++)entries.push({key:id+"-"+i,id:id,pet:p,level:petLevel(id),extra:count>3&&i===2?count-2:0})});return entries.slice(0,18)}
function movePets(){if(!state.petWalk)state.petWalk={};var now=Date.now();ownedPetEntries().forEach(function(entry,index){var spot=state.petWalk[entry.key];if(!spot){spot={x:12+(index*17)%76,y:20+(index*23)%66,nextAt:0,restUntil:0}}if(now>=spot.nextAt&&now>=spot.restUntil){var resting=stockRoll(Math.floor(now/PET_WALK_MS),entry.key,211)<.35;spot.x=8+Math.floor(stockRoll(Math.floor(now/PET_WALK_MS),entry.key,31)*84);spot.y=18+Math.floor(stockRoll(Math.floor(now/PET_WALK_MS),entry.key,47)*70);spot.restUntil=resting?now+PET_WALK_MS:0;spot.nextAt=now+PET_WALK_MS+(index%4)*650}state.petWalk[entry.key]=spot})}
function drawPets(){if(!el.petYard)return;movePets();el.petYard.innerHTML="";ownedPetEntries().forEach(function(entry){var spot=state.petWalk&&state.petWalk[entry.key]||{x:50,y:50},node=document.createElement("div");node.className="yard-pet rarity-"+entry.pet.rarity.toLowerCase();node.style.left=spot.x+"%";node.style.top=spot.y+"%";node.innerHTML="<span>"+entry.pet.icon+"</span><small>Lv "+entry.level+(entry.extra?"+":"")+"</small>";node.title=entry.pet.name+" Lv "+entry.level+(spot.restUntil>Date.now()?" resting":" walking");el.petYard.appendChild(node)})}
function plotClick(i){var p=state.plots[i];if(state.selectedType==="gear"){useGear(i);return}if(!p){plant(i);return}if(Date.now()-p.at>=p.duration){harvest(i);return}say("That crop is still growing.")}
function plant(i){var c=crop(state.selected);if(!c||state.selectedType!=="seed"){say("Choose a seed first.");return}if((state.seeds[c.id]||0)<1){state.selected=null;state.selectedType=null;render();say("You do not have any "+c.name+" seeds.");return}state.seeds[c.id]--;var muts=[];var pb=petBonuses();maybeAddMutation(muts,"gold",.05+pb.gold);maybeAddMutation(muts,"rainbow",.012+pb.rainbow);maybeAddMutation(muts,activeWeather().mutation,.18+pb.weather);var harvestCount=(c.multi||1)+pb.harvests;state.plots[i]={id:c.id,at:Date.now(),duration:growMs(c),harvestsLeft:harvestCount,totalHarvests:harvestCount,mutations:muts};state.stats.plantedToday++;state.stats.seedsPlanted++;render();save();say("Planted "+c.name+".")}
function harvest(i){var p=state.plots[i],c=crop(p.id),amt=1+up("yield").bonus+petBonuses().yield,weight=rollWeight(c,p.sizeBoost),key=inventoryKey(c.id,p.mutations,weight);state.crops[key]=(state.crops[key]||0)+amt;p.sizeBoost=0;p.mutationBoost=0;p.harvestsLeft=p.harvestsLeft||1;p.harvestsLeft--;if(p.harvestsLeft>0){p.at=Date.now();p.duration=Math.max(4000,Math.round(growMs(c)*(c.regrow||.6)));p.totalHarvests=p.totalHarvests||c.multi||1;say("Harvested "+amt+" "+weightLabel(weight)+" "+c.name+". The plant will regrow for "+p.harvestsLeft+" more harvest"+(p.harvestsLeft===1?"":"s")+".");}else{state.plots[i]=null;say("Harvested "+amt+" "+weightLabel(weight)+" "+c.name+".");}render();save();pulse(el.inventory)}
function gridCols(){var first=el.gardenGrid&&el.gardenGrid.querySelector(".plot");if(!first)return Math.max(1,Math.round(Math.sqrt(plotLimit())));return Math.max(1,Math.round(el.gardenGrid.clientWidth/first.getBoundingClientRect().width))}
function nearbyPlots(i){var cols=gridCols(),row=Math.floor(i/cols),col=i%cols,spots=[];for(var r=row-1;r<=row+1;r++)for(var c=col-1;c<=col+1;c++){var idx=r*cols+c;if(r>=0&&c>=0&&idx>=0&&idx<state.plots.length&&Math.floor(idx/cols)===r)spots.push(idx)}return spots}
function speedPlot(p,factor){var now=Date.now(),elapsed=now-p.at,remaining=Math.max(1000,(p.duration||0)-elapsed);p.duration=elapsed+Math.ceil(remaining*(1-factor))}
function useSprinkler(i,g){var count=0;nearbyPlots(i).forEach(function(idx){var p=state.plots[idx];if(!p)return;speedPlot(p,g.speed);p.sizeBoost=Math.min(3,(p.sizeBoost||0)+g.size);p.mutationBoost=Math.min(.65,(p.mutationBoost||0)+(g.mutation||0));count++});if(!count){say(g.name+" needs at least one planted crop in its 3x3 area.");return false}say(g.name+" watered "+count+" plant"+(count===1?"":"s")+", boosting growth, fruit size, and mutation rates.");return true}
function useGear(i){var g=gear(state.selected),p=state.plots[i];if(!g){say("Select gear first.");return}if(!p&&!g.sprinkler){say(g.name+" needs a planted plot.");return}if((state.gear[g.id]||0)<1){state.selected=null;state.selectedType=null;render();say("You do not have any "+g.name+" left.");return}var used=true;if(g.sprinkler)used=useSprinkler(i,g);else if(g.id==="shovel"){state.plots[i]=null;say("Removed the plant with a Shovel.")}else if(g.id==="reclaimer"){state.seeds[p.id]=(state.seeds[p.id]||0)+1;state.plots[i]=null;say("Reclaimed the plant and recovered a "+crop(p.id).name+" seed.")}else if(g.id==="wateringCan"){speedPlot(p,.5);say("Watering Can sped up the crop.")}if(!used)return;state.gear[g.id]--;render();save()}
function shopSlot(){return Math.floor(Date.now()/SHOP_RESTOCK_MS)}
function slotEnd(slot){return (slot+1)*SHOP_RESTOCK_MS}
function eventShopSlot(){return Math.floor(Date.now()/EVENT_RESTOCK_MS)}
function eventSlotEnd(slot){return (slot+1)*EVENT_RESTOCK_MS}
function seededRand(seed){var t=seed+0x6D2B79F5;t=Math.imul(t^t>>>15,t|1);t^=t+Math.imul(t^t>>>7,t|61);return ((t^t>>>14)>>>0)/4294967296}
function stockRoll(slot,id,salt){var seed=slot;for(var i=0;i<id.length;i++)seed=Math.imul(seed^id.charCodeAt(i),2654435761);return seededRand(seed+(salt||0))}
function restockAmount(rarity,slot,id){var r=STOCK_RULES[rarity]||STOCK_RULES.Common;return r.min+Math.floor(stockRoll(slot,id,991)*(r.max-r.min+1))}
function rollShopStock(slot){slot=slot||shopSlot();var stock={};CROPS.forEach(function(c){if(c.packOnly)return;var r=STOCK_RULES[c.rarity]||STOCK_RULES.Common;if(stockRoll(slot,c.id,17)<r.chance)stock[c.id]=restockAmount(c.rarity,slot,c.id)});if(!stock.carrot)stock.carrot=restockAmount("Common",slot,"carrot");state.shop={stock:stock,slot:slot,nextAt:slotEnd(slot)};return stock}
function ensureShopStock(){if(!state.shop)state.shop={stock:{},slot:0,nextAt:0};if(!state.shop.stock)state.shop.stock={};var slot=shopSlot();if(state.shop.slot!==slot||!state.shop.nextAt){rollShopStock(slot);save();say("Seed Shop restocked.")}}
