function gearSlot(){return Math.floor(Date.now()/GEAR_RESTOCK_MS)}
function gearSlotEnd(slot){return (slot+1)*GEAR_RESTOCK_MS}
function eggSlot(){return Math.floor(Date.now()/EGG_RESTOCK_MS)}
function eggSlotEnd(slot){return (slot+1)*EGG_RESTOCK_MS}
