function ensureGearStock(){if(!state.gearShop)state.gearShop={stock:{},slot:0,nextAt:0};if(!state.gearShop.stock)state.gearShop.stock={};var slot=gearSlot();if(state.gearShop.slot!==slot||!state.gearShop.nextAt){rollGearStock(slot);save();say("Gear Shop restocked.")}}
