function ensureEggStock(){if(!state.eggShop)state.eggShop={stock:{},slot:0,nextAt:0};if(!state.eggShop.stock)state.eggShop.stock={};var slot=eggSlot();if(state.eggShop.slot!==slot||!state.eggShop.nextAt){rollEggStock(slot);save();say("Pet Shop eggs restocked.")}}
