function drawShop(){ensureShopStock();el.shop.innerHTML="";var timer=row("\u23F1","Seed Shop Restock: "+time(state.shop.nextAt-Date.now()),"New limited stock arrives every 5 minutes. Rarer seeds appear less often; Prismatic seeds have a 0.05% stock chance.");timer.classList.add("restock-item");el.shop.appendChild(timer);CROPS.filter(function(c){return !c.packOnly}).slice().sort(function(a,b){return rarityRank(a.rarity)-rarityRank(b.rarity)||a.seedCost-b.seedCost||a.name.localeCompare(b.name)}).forEach(function(c){var available=stockLeft(c.id),need=unlockCost(c),unlocked=state.coins>=need||need===0||(state.seeds[c.id]||0)>0||(state.crops[c.id]||0)>0;var stocked=available>0,canBuy=unlocked&&stocked&&state.coins>=c.seedCost;var meta=unlocked?c.rarity+" - Stock: "+available+" - "+c.desc+" - "+((c.multi||1)>1?c.multi+" harvests - ":"")+"grows in "+time(growMs(c))+" - sells for "+num(c.sell):"Unlock when you reach "+num(need)+" coins.";if(!stocked)meta=unlocked?c.rarity+" - Out of stock until next restock.":meta;var item=row(c.icon,c.name+" Seed",meta,c.rarity);item.querySelector(".actions").append(btn(!unlocked?"Locked":stocked?"Buy "+num(c.seedCost):"Out",!canBuy,function(){buySeed(c.id,1)}),btn("Quick Buy",!canBuy,function(){quickBuySeed(c.id)}),btn("Select",(state.seeds[c.id]||0)<1,function(){selectSeed(c.id)}));el.shop.appendChild(item)})}
function drawGearShop(){ensureGearStock();el.gearShop.innerHTML="";var timer=row("\u23F1","Gear Shop Restock: "+time(state.gearShop.nextAt-Date.now()),"Shared limited gear stock refreshes every 5 minutes.");timer.classList.add("restock-item");el.gearShop.appendChild(timer);GEAR.forEach(function(g){var stock=gearStockLeft(g.id),canBuy=stock>0&&state.coins>=g.cost,bundle=g.bundle||1,bundleText=bundle>1?" - Bundle: "+bundle:"";var item=row(g.icon,g.name,g.desc+" Cost: "+num(g.cost)+" coins"+bundleText+" - Stock: "+stock+" - Owned: "+(state.gear[g.id]||0));item.querySelector(".actions").append(btn(stock>0?"Buy "+(bundle>1?bundle+" for ":"")+num(g.cost):"Out",!canBuy,function(){buyGear(g.id,1)}),btn("Quick Buy",!canBuy,function(){quickBuyGear(g.id)}),btn("Select",(state.gear[g.id]||0)<1,function(){selectGear(g.id)}));el.gearShop.appendChild(item)})}
function quickBuySeed(id){var c=crop(id),available=stockLeft(id),affordable=Math.floor(state.coins/c.seedCost),max=Math.min(available,affordable);if(max<1){say("You cannot buy any "+c.name+" seeds right now.");return}var raw=prompt("How many "+c.name+" seeds do you want to buy? Max: "+max,max);if(raw===null)return;var qty=Math.floor(Number(raw));if(!qty||qty<1){say("Quick buy cancelled.");return}buySeed(id,qty)}
