function quickBuyGear(id){var g=gear(id),stock=gearStockLeft(id),max=Math.min(stock,Math.floor(state.coins/g.cost)),bundle=g.bundle||1;if(max<1){say(stock<1?g.name+" is out of stock.":"Not enough coins for "+g.name+".");return}var raw=prompt("How many "+g.name+" purchase"+(max===1?"":"s")+" do you want? Max: "+max+(bundle>1?". Each purchase gives "+bundle+".":""),max);if(raw===null)return;var qty=Math.floor(Number(raw));if(!qty||qty<1){say("Quick buy cancelled.");return}buyGear(id,qty)}
function buyGear(id,qty){var g=gear(id);ensureGearStock();qty=Math.max(1,Math.floor(Number(qty)||1));var stock=gearStockLeft(id),affordable=Math.floor(state.coins/g.cost),buyQty=Math.min(qty,stock,affordable),bundle=g.bundle||1,totalItems=buyQty*bundle;if(stock<1){say(g.name+" is out of stock until the next restock.");return}if(affordable<1){say("Not enough coins for "+g.name+".");return}state.coins-=g.cost*buyQty;state.gearShop.stock[id]-=buyQty;state.gear[id]=(state.gear[id]||0)+totalItems;state.selected=id;state.selectedType="gear";render();save();say("Bought "+totalItems+" "+g.name+(totalItems===1?"":"s")+(buyQty<qty?" (limited by stock or coins).":"."))}
